#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")
with open("screens/KnockingSessionScreen.js", "wb") as f:
    f.write(base64.b64decode(""))
print("OK screens/KnockingSessionScreen.js")
print()
print("Now install TF.js packages:")
print("  npx expo install @tensorflow/tfjs @tensorflow/tfjs-react-native expo-asset expo-file-system expo-gl")
print()
print("Then build the dev build (NOT expo start — TF.js needs native modules):")
print("  eas build --platform ios --profile development")
print()
print("After install on phone, the session screen will show:")
print("  Green dot = ML knock detection active")
print("  Orange dot = Amplitude detection active (fallback)")
